#!/usr/bin/env python3
"""
meshctl: Manage mesh resources from YAML specs
"""

import argparse
import json
import os
import re
import sys
from typing import Any, Dict, List, Optional, Tuple

import yaml


# Persistent storage for meshes (in-memory for this implementation)
MESHES_STORE: Dict[str, Dict[str, Any]] = {}
STORAGE_FILE = "meshes.json"


def load_storage() -> None:
    """Load persisted meshes from disk."""
    global MESHES_STORE
    if os.path.exists(STORAGE_FILE):
        try:
            with open(STORAGE_FILE, 'r') as f:
                MESHES_STORE = json.load(f)
        except (json.JSONDecodeError, IOError):
            MESHES_STORE = {}


def save_storage() -> None:
    """Persist meshes to disk."""
    with open(STORAGE_FILE, 'w') as f:
        json.dump(MESHES_STORE, f, indent=2)


class Error:
    """Error object for validation and operation errors."""
    def __init__(self, field: str, message: str, error_type: str):
        self.field = field
        self.message = message
        self.type = error_type

    def to_dict(self) -> Dict[str, str]:
        return {
            "field": self.field,
            "message": self.message,
            "type": self.type
        }


def output_errors(errors: List[Error]) -> None:
    """Output errors as JSON to stdout."""
    result = {"errors": [e.to_dict() for e in errors]}
    print(json.dumps(result))
    sys.exit(1)


def parse_memory_quantity(value: str) -> int:
    """
    Parse memory quantity string to bytes.
    Accepted forms: non-negative integer (bytes), or with Ki, Mi, Gi, Ti suffix.
    Returns bytes as integer.
    """
    if not isinstance(value, str):
        raise ValueError("Memory quantity must be a string")

    value = value.strip()
    if not value:
        raise ValueError("Memory quantity cannot be empty")

    # Check for suffix
    suffix_multipliers = {
        'Ki': 1024,
        'Mi': 1024 * 1024,
        'Gi': 1024 * 1024 * 1024,
        'Ti': 1024 * 1024 * 1024 * 1024,
    }

    for suffix, multiplier in suffix_multipliers.items():
        if value.endswith(suffix):
            num_str = value[:-len(suffix)]
            if not num_str.isdigit() and not (num_str.startswith('0') and num_str != '0'):
                try:
                    num = int(num_str)
                except ValueError:
                    raise ValueError(f"Invalid memory format: {value}")
            else:
                try:
                    num = int(num_str)
                except ValueError:
                    raise ValueError(f"Invalid memory format: {value}")
            if num < 0:
                raise ValueError(f"Memory must be non-negative: {value}")
            return num * multiplier

    # Plain integer (bytes)
    if not value.isdigit() and not (value.startswith('0') and value != '0'):
        try:
            int(value)
        except ValueError:
            raise ValueError(f"Invalid memory format: {value}")
    try:
        num = int(value)
    except ValueError:
        raise ValueError(f"Invalid memory format: {value}")
    if num < 0:
        raise ValueError(f"Memory must be non-negative: {value}")
    return num


def parse_cpu_quantity(value: str) -> int:
    """
    Parse CPU quantity string to milli-cores.
    Accepted forms: non-negative integer core count, or with 'm' suffix.
    Returns milli-cores as integer.
    """
    if not isinstance(value, str):
        raise ValueError("CPU quantity must be a string")

    value = value.strip()
    if not value:
        raise ValueError("CPU quantity cannot be empty")

    if value.endswith('m'):
        num_str = value[:-1]
        if not num_str.isdigit() and not (num_str.startswith('0') and num_str != '0'):
            try:
                int(num_str)
            except ValueError:
                raise ValueError(f"Invalid CPU format: {value}")
        try:
            num = int(num_str)
        except ValueError:
            raise ValueError(f"Invalid CPU format: {value}")
        if num < 0:
            raise ValueError(f"CPU must be non-negative: {value}")
        return num
    else:
        # Plain integer (cores)
        if not value.isdigit() and not (value.startswith('0') and value != '0'):
            try:
                int(value)
            except ValueError:
                raise ValueError(f"Invalid CPU format: {value}")
        try:
            num = int(value)
        except ValueError:
            raise ValueError(f"Invalid CPU format: {value}")
        if num < 0:
            raise ValueError(f"CPU must be non-negative: {value}")
        return num * 1000


def validate_name(name: Any) -> List[Error]:
    """Validate metadata.name field."""
    errors = []

    if name is None:
        errors.append(Error("metadata.name", "name is required", "required"))
        return errors

    if not isinstance(name, str):
        errors.append(Error("metadata.name", "name must be a string", "invalid"))
        return errors

    if name == "":
        errors.append(Error("metadata.name", "name cannot be empty", "required"))
        return errors

    # Must match ^[a-z0-9][a-z0-9-]*[a-z0-9]$
    # Minimum length 2
    if len(name) < 2:
        errors.append(Error("metadata.name", "name must be at least 2 characters", "invalid"))
        return errors

    pattern = r'^[a-z0-9][a-z0-9-]*[a-z0-9]$'
    if not re.match(pattern, name):
        errors.append(Error("metadata.name", "name must match ^[a-z0-9][a-z0-9-]*[a-z0-9]$", "invalid"))

    return errors


def validate_runtime(runtime: Any) -> List[Error]:
    """Validate spec.runtime field."""
    errors = []

    if runtime is None:
        return errors

    if not isinstance(runtime, str):
        errors.append(Error("spec.runtime", "runtime must be a string", "invalid"))
        return errors

    # Must be semantic version major.minor.patch
    pattern = r'^\d+\.\d+\.\d+$'
    if not re.match(pattern, runtime):
        errors.append(Error("spec.runtime", "runtime must be semantic version major.minor.patch", "invalid"))

    return errors


def validate_instances(instances: Any) -> List[Error]:
    """Validate spec.instances field."""
    errors = []

    if instances is None:
        return errors

    if not isinstance(instances, int):
        errors.append(Error("spec.instances", "instances must be an integer", "invalid"))
        return errors

    if instances <= 0:
        errors.append(Error("spec.instances", "instances must be positive", "invalid"))

    return errors


def validate_resources_memory(memory: Any) -> List[Error]:
    """Validate spec.resources.memory field."""
    errors = []

    if memory is None:
        return errors

    if not isinstance(memory, dict):
        errors.append(Error("spec.resources.memory", "resources.memory must be an object", "invalid"))
        return errors

    # limit is required when memory is present
    if 'limit' not in memory:
        errors.append(Error("spec.resources.memory.limit", "memory limit is required", "required"))
        return errors

    # Validate limit format
    try:
        limit_bytes = parse_memory_quantity(memory['limit'])
    except ValueError as e:
        errors.append(Error("spec.resources.memory.limit", str(e), "invalid"))
        return errors  # Can't validate request if limit is invalid

    # Validate request if present
    if 'request' in memory:
        request_val = memory['request']
        if request_val is not None:
            try:
                request_bytes = parse_memory_quantity(request_val)
                if request_bytes > limit_bytes:
                    errors.append(Error("spec.resources.memory.request",
                                       "request cannot exceed limit", "invalid"))
            except ValueError as e:
                errors.append(Error("spec.resources.memory.request", str(e), "invalid"))

    return errors


def validate_resources_cpu(cpu: Any) -> List[Error]:
    """Validate spec.resources.cpu field."""
    errors = []

    if cpu is None:
        return errors

    if not isinstance(cpu, dict):
        errors.append(Error("spec.resources.cpu", "resources.cpu must be an object", "invalid"))
        return errors

    # limit is required when cpu is present
    if 'limit' not in cpu:
        errors.append(Error("spec.resources.cpu.limit", "cpu limit is required", "required"))
        return errors

    # Validate limit format
    try:
        limit_milli = parse_cpu_quantity(cpu['limit'])
    except ValueError as e:
        errors.append(Error("spec.resources.cpu.limit", str(e), "invalid"))
        return errors  # Can't validate request if limit is invalid

    # Validate request if present
    if 'request' in cpu:
        request_val = cpu['request']
        if request_val is not None:
            try:
                request_milli = parse_cpu_quantity(request_val)
                if request_milli > limit_milli:
                    errors.append(Error("spec.resources.cpu.request",
                                       "request cannot exceed limit", "invalid"))
            except ValueError as e:
                errors.append(Error("spec.resources.cpu.request", str(e), "invalid"))

    return errors


def validate_migration_strategy(strategy: Any) -> List[Error]:
    """Validate spec.migration.strategy field."""
    errors = []

    if strategy is None:
        return errors

    if not isinstance(strategy, str):
        errors.append(Error("spec.migration.strategy", "migration strategy must be a string", "invalid"))
        return errors

    if strategy != "FullStop":
        errors.append(Error("spec.migration.strategy", "migration strategy must be 'FullStop'", "invalid"))

    return errors


def find_auto_scaling(obj: Any, path: str = "spec") -> List[Error]:
    """Recursively find autoScaling fields under spec."""
    errors = []

    if not isinstance(obj, dict):
        return errors

    if 'autoScaling' in obj:
        errors.append(Error(path, "autoScaling is forbidden", "forbidden"))
        # Don't recurse into autoScaling
        return errors

    for key, value in obj.items():
        new_path = f"{path}.{key}" if path else key
        if isinstance(value, dict):
            errors.extend(find_auto_scaling(value, new_path))

    return errors


def validate_yaml_data(data: Any, is_create: bool = True) -> List[Error]:
    """Validate the parsed YAML data."""
    errors = []

    # Must be a mapping
    if not isinstance(data, dict):
        errors.append(Error("", "YAML document must be a mapping", "parse"))
        return errors

    # Check for top-level keys
    if 'metadata' not in data:
        errors.append(Error("metadata", "metadata is required", "required"))
        return errors

    if 'spec' not in data:
        errors.append(Error("spec", "spec is required", "required"))
        return errors

    metadata = data.get('metadata')
    spec = data.get('spec')

    # Validate metadata.name
    if metadata is not None:
        errors.extend(validate_name(metadata.get('name')))

    # Validate spec fields
    if spec is not None:
        # Validate instances
        errors.extend(validate_instances(spec.get('instances')))

        # Validate runtime
        errors.extend(validate_runtime(spec.get('runtime')))

        # Validate resources
        if 'resources' in spec:
            resources = spec['resources']
            if isinstance(resources, dict):
                errors.extend(validate_resources_memory(resources.get('memory')))
                errors.extend(validate_resources_cpu(resources.get('cpu')))

        # Validate migration.strategy
        if 'migration' in spec:
            migration = spec['migration']
            if isinstance(migration, dict):
                errors.extend(validate_migration_strategy(migration.get('strategy')))

        # Check for forbidden autoScaling fields
        errors.extend(find_auto_scaling(spec))

    # Check for duplicate on create
    if is_create and metadata is not None:
        name = metadata.get('name')
        if name and name in MESHES_STORE:
            errors.append(Error("metadata.name", f"mesh '{name}' already exists", "duplicate"))

    # For describe/delete, check if mesh exists
    # (handled by caller)

    return errors


def apply_defaults(data: Dict[str, Any]) -> Dict[str, Any]:
    """Apply default values to the data."""
    result = {
        "metadata": {},
        "spec": {},
        "status": {"state": "Running"}
    }

    # Copy metadata
    if 'metadata' in data and isinstance(data['metadata'], dict):
        result['metadata'] = dict(data['metadata'])

    # Copy spec and apply defaults
    spec = data.get('spec', {})
    if not isinstance(spec, dict):
        spec = {}

    result['spec'] = {}

    # instances: default 1
    result['spec']['instances'] = spec.get('instances', 1)

    # runtime: omit when absent (no default)
    if 'runtime' in spec:
        result['spec']['runtime'] = spec['runtime']

    # resources
    resources = spec.get('resources', {})
    if isinstance(resources, dict):
        result['spec']['resources'] = {}

        # memory: Omit the whole object to get {"limit": "1Gi", "request": "1Gi"}
        memory = resources.get('memory')
        if memory is None:
            # Memory object was completely omitted, add with defaults
            result['spec']['resources']['memory'] = {"limit": "1Gi", "request": "1Gi"}
        elif isinstance(memory, dict):
            result['spec']['resources']['memory'] = {}
            if 'limit' in memory:
                result['spec']['resources']['memory']['limit'] = memory['limit']
            # request defaults to limit
            if 'request' in memory:
                result['spec']['resources']['memory']['request'] = memory['request']
            else:
                # If limit is present, request defaults to limit
                if 'limit' in memory:
                    result['spec']['resources']['memory']['request'] = memory['limit']

        # cpu: omit when absent
        cpu = resources.get('cpu')
        if cpu is not None and isinstance(cpu, dict):
            result['spec']['resources']['cpu'] = {}
            if 'limit' in cpu:
                result['spec']['resources']['cpu']['limit'] = cpu['limit']
            if 'request' in cpu:
                result['spec']['resources']['cpu']['request'] = cpu['request']
            # request defaults to limit when present but no request
            elif 'limit' in cpu:
                result['spec']['resources']['cpu']['request'] = cpu['limit']

    # access.authentication.enabled: default true
    access = spec.get('access', {})
    if isinstance(access, dict):
        authentication = access.get('authentication')
        if authentication is not None and isinstance(authentication, dict):
            result['spec']['access'] = {'authentication': {}}
            if 'enabled' in authentication:
                result['spec']['access']['authentication']['enabled'] = authentication['enabled']
            else:
                result['spec']['access']['authentication']['enabled'] = True
        else:
            # Default to true when access exists but no authentication
            result['spec']['access'] = {'authentication': {'enabled': True}}
    else:
        # Default: authentication enabled
        result['spec']['access'] = {'authentication': {'enabled': True}}

    # migration.strategy: default "FullStop"
    migration = spec.get('migration', {})
    if isinstance(migration, dict):
        result['spec']['migration'] = {'strategy': migration.get('strategy', 'FullStop')}
    else:
        result['spec']['migration'] = {'strategy': 'FullStop'}

    return result


def read_yaml_file(path: str) -> Tuple[Optional[Dict[str, Any]], List[Error]]:
    """Read and parse a YAML file."""
    errors = []

    try:
        with open(path, 'r') as f:
            content = f.read()
    except IOError as e:
        errors.append(Error("", f"Cannot read file: {e}", "parse"))
        return None, errors

    try:
        data = yaml.safe_load(content)
    except yaml.YAMLError as e:
        errors.append(Error("", f"Cannot parse YAML: {e}", "parse"))
        return None, errors

    return data, errors


def cmd_create(file_path: str) -> None:
    """Handle mesh create command."""
    load_storage()

    data, errors = read_yaml_file(file_path)
    if errors:
        output_errors(errors)

    # Validate
    errors = validate_yaml_data(data, is_create=True)
    if errors:
        output_errors(errors)

    # Apply defaults
    full_resource = apply_defaults(data)

    # Persist
    name = full_resource['metadata']['name']
    MESHES_STORE[name] = full_resource
    save_storage()

    # Output full resource
    print(json.dumps(full_resource))


def cmd_list() -> None:
    """Handle mesh list command."""
    load_storage()

    # Create list of summaries sorted by name ascending, case-sensitive
    meshes = []
    for name in sorted(MESHES_STORE.keys()):
        mesh = MESHES_STORE[name]
        meshes.append({
            "name": name,
            "status": mesh.get('status', {"state": "Unknown"})
        })

    print(json.dumps(meshes))


def cmd_describe(name: str) -> None:
    """Handle mesh describe command."""
    load_storage()

    # Check if mesh exists
    if name not in MESHES_STORE:
        errors = [Error("metadata.name", f"mesh '{name}' not found", "not_found")]
        output_errors(errors)

    print(json.dumps(MESHES_STORE[name]))


def cmd_delete(name: str) -> None:
    """Handle mesh delete command."""
    load_storage()

    # Check if mesh exists
    if name not in MESHES_STORE:
        errors = [Error("metadata.name", f"mesh '{name}' not found", "not_found")]
        output_errors(errors)

    # Delete
    del MESHES_STORE[name]
    save_storage()

    # Output confirmation
    result = {
        "message": f"Mesh '{name}' deleted successfully",
        "metadata": {"name": name}
    }
    print(json.dumps(result))


def main() -> None:
    parser = argparse.ArgumentParser(
        prog='meshctl',
        description='Manage mesh resources from YAML specs'
    )
    subparsers = parser.add_subparsers(dest='command', required=True)

    # mesh subcommand
    mesh_parser = subparsers.add_parser('mesh', help='Manage mesh resources')
    mesh_subparsers = mesh_parser.add_subparsers(dest='operation', required=True)

    # mesh create
    create_parser = mesh_subparsers.add_parser('create', help='Create a mesh from YAML')
    create_parser.add_argument('-f', '--file', required=True, help='YAML file path')

    # mesh list
    mesh_subparsers.add_parser('list', help='List all meshes')

    # mesh describe
    describe_parser = mesh_subparsers.add_parser('describe', help='Describe a mesh')
    describe_parser.add_argument('name', help='Mesh name')

    # mesh delete
    delete_parser = mesh_subparsers.add_parser('delete', help='Delete a mesh')
    delete_parser.add_argument('name', help='Mesh name')

    args = parser.parse_args()

    if args.command == 'mesh':
        if args.operation == 'create':
            cmd_create(args.file)
        elif args.operation == 'list':
            cmd_list()
        elif args.operation == 'describe':
            cmd_describe(args.name)
        elif args.operation == 'delete':
            cmd_delete(args.name)


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""meshctl: Mesh Lifecycle and Topology Control Tool"""

import argparse
import json
import os
import sys
from typing import Any, Optional

import yaml

# Persistent storage directory
STORAGE_DIR = ".mesh_storage"
DEFAULT_STORAGE_SIZE = "1Gi"


def ensure_storage() -> None:
    if not os.path.exists(STORAGE_DIR):
        os.makedirs(STORAGE_DIR)


def get_mesh_path(name: str) -> str:
    return os.path.join(STORAGE_DIR, f"{name}.json")


def load_mesh(name: str) -> Optional[dict]:
    p = get_mesh_path(name)
    if not os.path.exists(p):
        return None
    with open(p, "r") as f:
        return json.load(f)


def save_mesh(name: str, data: dict) -> None:
    ensure_storage()
    with open(get_mesh_path(name), "w") as f:
        json.dump(data, f, indent=2)


def delete_mesh(name: str) -> bool:
    p = get_mesh_path(name)
    if os.path.exists(p):
        os.remove(p)
        return True
    return False


def mesh_exists(name: str) -> bool:
    return os.path.exists(get_mesh_path(name))


def list_mesh_names() -> list:
    ensure_storage()
    names = []
    for fn in os.listdir(STORAGE_DIR):
        if fn.endswith(".json"):
            names.append(fn[:-5])
    return sorted(names)


def to_json_error(field: str, error_type: str, message: str) -> dict:
    return {"field": field, "type": error_type, "message": message}


def output_errors(errors: list, exit_code: int = 1) -> None:
    print(json.dumps({"errors": errors}, indent=2))
    sys.exit(exit_code)


def output_result(data: dict) -> None:
    print(json.dumps(data, indent=2))


def err_not_found(name: str) -> None:
    output_errors([to_json_error("metadata.name", "not_found", f"mesh '{name}' not found")])


def parse_yaml(path: str) -> tuple[Optional[dict], list]:
    errors = []
    try:
        with open(path, "r") as f:
            content = f.read()
    except IOError as e:
        errors.append(to_json_error("", "parse", f"cannot read file: {e}"))
        return None, errors
    try:
        data = yaml.safe_load(content)
    except yaml.YAMLError as e:
        errors.append(to_json_error("", "parse", f"cannot parse YAML: {e}"))
        return None, errors
    return data, errors


def is_valid_memory_quantity(val: Any) -> bool:
    if not isinstance(val, str):
        return False
    import re
    m = re.match(r"^(\d+)(Ki|Mi|Gi|Ti)?$", val, re.IGNORECASE)
    if not m:
        return False
    return int(m.group(1)) >= 0


def validate_storage(storage: Any, field_path: str, errors: list) -> list:
    if storage is None:
        return errors
    if not isinstance(storage, dict):
        errors.append(to_json_error(f"{field_path}.storage", "invalid",
                                    f"{field_path}.storage must be an object"))
        return errors
    size = storage.get("size")
    if size is not None and not is_valid_memory_quantity(size):
        errors.append(to_json_error(f"{field_path}.storage.size", "invalid",
                                    f"{field_path}.storage.size must be a valid memory quantity (got '{size}')"))
    ephemeral = storage.get("ephemeral")
    if ephemeral is not None and not isinstance(ephemeral, bool):
        errors.append(to_json_error(f"{field_path}.storage.ephemeral", "invalid",
                                    "spec.network.storage.ephemeral must be a boolean"))
    cls = storage.get("className")
    if cls is not None and not isinstance(cls, str):
        errors.append(to_json_error(f"{field_path}.storage.className", "invalid",
                                    "spec.network.storage.className must be a string"))
    return errors


def validate_mesh(data: dict, is_update: bool = False, original_mesh: Optional[dict] = None) -> list:
    errors = []
    if not isinstance(data, dict):
        errors.append(to_json_error("", "parse", "YAML must be a mapping"))
        return errors
    # metadata.name required
    meta = data.get("metadata")
    if not isinstance(meta, dict):
        errors.append(to_json_error("metadata", "required", "metadata is required"))
        return errors
    name = meta.get("name")
    if not name:
        errors.append(to_json_error("metadata.name", "required", "name is required"))
    elif not isinstance(name, str):
        errors.append(to_json_error("metadata.name", "invalid", "metadata.name must be a string"))
    # spec required
    spec = data.get("spec")
    if not isinstance(spec, dict):
        errors.append(to_json_error("spec", "required", "spec is required"))
        return errors
    # instances: non-negative integer
    instances = spec.get("instances")
    if instances is not None and not isinstance(instances, int):
        errors.append(to_json_error("spec.instances", "invalid", "spec.instances must be a non-negative integer"))
    elif instances is not None and instances < 0:
        errors.append(to_json_error("spec.instances", "invalid", "spec.instances must be a non-negative integer"))
    # network
    network = spec.get("network")
    if network is not None:
        if not isinstance(network, dict):
            errors.append(to_json_error("spec.network", "invalid", "spec.network must be an object"))
        else:
            storage = network.get("storage")
            errors = validate_storage(storage, "spec.network", errors)
            rf = network.get("replicationFactor")
            if rf is not None:
                if not isinstance(rf, int) or rf < 1:
                    errors.append(to_json_error("spec.network.replicationFactor", "invalid",
                                                 f"spec.network.replicationFactor must be a positive integer (got '{rf}')"))
                elif instances is not None and rf > instances:
                    errors.append(to_json_error("spec.network.replicationFactor", "invalid",
                                                 f"spec.network.replicationFactor ({rf}) must not exceed spec.instances ({instances})"))
    # Immutability check on update
    if is_update and original_mesh:
        orig_storage = original_mesh.get("spec", {}).get("network", {}).get("storage")
        new_storage = spec.get("network", {}).get("storage")
        if orig_storage and new_storage:
            orig_size = orig_storage.get("size")
            new_size = new_storage.get("size")
            if orig_size is not None and new_size is not None and orig_size != new_size:
                errors.append(to_json_error("spec.network.storage.size", "immutable",
                                            "field 'spec.network.storage.size' is immutable after creation"))
    return errors


def storage_output(storage: dict) -> dict:
    if storage.get("ephemeral"):
        return {"ephemeral": True}
    return {"ephemeral": storage.get("ephemeral", False), "size": storage["size"]}


def default_replication_factor(instances: int) -> int:
    return 1 if instances > 0 else 1  # computed default based on instances


def create_conditions() -> list:
    return [
        {"type": "Healthy", "status": "True", "message": ""},
        {"type": "PrechecksPassed", "status": "True", "message": ""}
    ]


def create_status(spec: dict) -> dict:
    instances = spec.get("instances")
    if instances is None:
        instances = 0
    if instances > 0:
        state = "Running"
        ready = instances
        starting = 0
        stopped = 0
    else:
        state = "Stopped"
        ready = 0
        starting = 0
        stopped = 0
    return {
        "state": state,
        "stable": True,
        "conditions": create_conditions(),
        "instances": {"ready": ready, "starting": starting, "stopped": stopped}
    }


def apply_defaults(data: dict) -> dict:
    """Apply defaults not already set."""
    spec = data.get("spec", {})
    network = spec.get("network", {})
    storage = network.get("storage")
    if isinstance(storage, dict) and "size" not in storage:
        storage["size"] = DEFAULT_STORAGE_SIZE
    if "instances" not in spec:
        spec["instances"] = 0
    if "replicationFactor" not in network or network.get("replicationFactor") is None:
        network["replicationFactor"] = default_replication_factor(spec["instances"])
    if "network" in spec:
        spec["network"] = network
    data["spec"] = spec
    return data


def sort_conditions(conditions: list) -> None:
    conditions.sort(key=lambda c: c["type"])


def has_condition(conditions: list, cond_type: str) -> bool:
    return any(c["type"] == cond_type for c in conditions)


def filter_condition(conditions: list, cond_type: str) -> list:
    """Remove condition of given type."""
    return [c for c in conditions if c["type"] != cond_type]


def cmd_create(args) -> None:
    data, errors = parse_yaml(args.file)
    if errors:
        output_errors(errors)
    name = data.get("metadata", {}).get("name")
    if not name:
        output_errors([to_json_error("metadata.name", "required", "name is required")])
    if mesh_exists(name):
        output_errors([to_json_error("metadata.name", "already_exists", f"mesh '{name}' already exists")])
    errors = validate_mesh(data)
    if errors:
        output_errors(errors)
    data = apply_defaults(data)
    data["status"] = create_status(data["spec"])
    save_mesh(name, data)
    output_result(data)


def cmd_list(args) -> None:
    names = list_mesh_names()
    result = []
    for n in names:
        m = load_mesh(n)
        st = m.get("status", {})
        result.append({
            "name": n,
            "instances": m["spec"].get("instances", 0),
            "state": st.get("state", "Unknown"),
            "stable": st.get("stable", True)
        })
    output_result(result)


def cmd_describe(args) -> None:
    name = args.name
    if not mesh_exists(name):
        err_not_found(name)
    mesh = load_mesh(name)
    # Apply post-describe state transitions
    spec = mesh["spec"]
    status = mesh.get("status", {})
    inst = status.get("instances", {})
    # Remove transient Scaling
    conditions = [c for c in status.get("conditions", []) if c["type"] != "Scaling"]
    # Update ready to match spec.instances and starting to 0
    new_instances = {
        "ready": spec.get("instances", 0),
        "starting": 0,
        "stopped": inst.get("stopped", 0)
    }
    status["instances"] = new_instances
    status["conditions"] = conditions
    status["stable"] = True
    status["state"] = "Running" if spec.get("instances", 0) > 0 else "Stopped"
    mesh["status"] = status
    sort_conditions(status["conditions"])
    save_mesh(name, mesh)
    output_result(mesh)


def cmd_delete(args) -> None:
    name = args.name
    if not mesh_exists(name):
        err_not_found(name)
    delete_mesh(name)
    output_result({"message": f"Mesh '{name}' deleted successfully", "metadata": {"name": name}})


def cmd_update(args) -> None:
    data, errors = parse_yaml(args.file)
    if errors:
        output_errors(errors)
    name = data.get("metadata", {}).get("name")
    if not name:
        output_errors([to_json_error("metadata.name", "required", "metadata.name is required")])
    if not mesh_exists(name):
        err_not_found(name)
    original = load_mesh(name)
    # Validate update
    errors = validate_mesh(data, is_update=True, original_mesh=original)
    if errors:
        output_errors(errors)
    # Merge update spec into original
    new_spec = merge_spec(original["spec"], data["spec"])
    original["spec"] = new_spec
    # Compute new status based on lifecycle transitions
    status = apply_lifecycle_transitions(original, new_spec)
    original["status"] = status
    # Format storage output in spec
    net = original["spec"].get("network", {})
    if "storage" in net:
        net["storage"] = storage_output(net["storage"])
    original["spec"]["network"] = net
    save_mesh(name, original)
    sort_conditions(status["conditions"])
    output_result(original)


def merge_spec(orig_spec: dict, update_spec: dict) -> dict:
    merged = {k: v for k, v in orig_spec.items()}
    # Deep merge instances
    if "instances" in update_spec:
        merged["instances"] = update_spec["instances"]
    # Deep merge network
    orig_net = orig_spec.get("network", {})
    update_net = update_spec.get("network", {})
    merged_net = {k: v for k, v in orig_net.items()}
    if "storage" in update_net:
        # Merge storage field-by-field
        orig_storage = orig_net.get("storage", {})
        new_storage = update_net["storage"]
        merged_storage = {"size": orig_storage.get("size"),
                          "ephemeral": orig_storage.get("ephemeral", False),
                          "className": orig_storage.get("className")}
        if new_storage.get("size") is not None:
            merged_storage["size"] = new_storage["size"]
        if new_storage.get("ephemeral") is not None:
            merged_storage["ephemeral"] = new_storage["ephemeral"]
        if new_storage.get("className") is not None:
            merged_storage["className"] = new_storage["className"]
        merged_net["storage"] = merged_storage
    if "replicationFactor" in update_net:
        merged_net["replicationFactor"] = update_net["replicationFactor"]
    merged["network"] = merged_net
    return merged


def apply_lifecycle_transitions(mesh: dict, new_spec: dict) -> dict:
    """Compute new status based on lifecycle transitions."""
    orig_spec = mesh["spec"]
    orig_instances = orig_spec.get("instances", 0)
    new_instances = new_spec.get("instances", 0)
    orig_status = mesh.get("status", {})
    orig_conditions = list(orig_status.get("conditions", []))
    orig_inst_status = orig_status.get("instances", {})
    orig_ready = orig_inst_status.get("ready", orig_instances)
    orig_stopped = orig_inst_status.get("stopped", 0)

    # Handle resume from stopped first
    desired_resume = orig_status.get("desiredInstancesOnResume")
    is_stopped = orig_status.get("state") == "Stopped"
    was_stopped = desired_resume is not None and is_stopped

    if was_stopped and new_instances > 0:
        # Resume
        target = new_instances if new_instances > 0 else desired_resume
        # Remove GracefulShutdown and desiredInstancesOnResume
        orig_conditions = filter_condition(orig_conditions, "GracefulShutdown")
        new_status = {
            "state": "Running",
            "stable": False,
            "conditions": orig_conditions,
            "instances": {"ready": 0, "starting": target, "stopped": 0}
        }
        # Remove transiently
        if "desiredInstancesOnResume" in orig_status:
            del orig_status["desiredInstancesOnResume"]
        return new_status

    # Stop
    if orig_instances > 0 and new_instances == 0:
        orig_conditions.append({"type": "GracefulShutdown", "status": "True", "message": ""})
        total_stopped = orig_ready + orig_stopped
        return {
            "state": "Stopped",
            "stable": False,
            "conditions": orig_conditions,
            "instances": {"ready": 0, "starting": 0, "stopped": total_stopped},
            "desiredInstancesOnResume": orig_instances
        }

    # Scale up
    if new_instances > orig_instances:
        diff = new_instances - orig_instances
        orig_conditions.append({"type": "Scaling", "status": "True",
                                 "message": f"Scaling from {orig_instances} to {new_instances} instances"})
        return {
            "state": "Running",
            "stable": False,
            "conditions": orig_conditions,
            "instances": {"ready": orig_instances, "starting": diff, "stopped": orig_stopped}
        }

    # Scale down
    if new_instances < orig_instances:
        orig_conditions.append({"type": "Scaling", "status": "True", "message": ""})
        return {
            "state": "Running",
            "stable": False,
            "conditions": orig_conditions,
            "instances": {"ready": new_instances, "starting": 0, "stopped": orig_stopped}
        }

    # No change
    # Remove any transient Scaling from previous scale operations
    orig_conditions = filter_condition(orig_conditions, "Scaling")
    return {
        "state": "Running" if new_instances > 0 else "Stopped",
        "stable": True,
        "conditions": orig_conditions,
        "instances": {"ready": new_instances, "starting": 0, "stopped": orig_stopped}
    }


def main() -> None:
    parser = argparse.ArgumentParser(prog="meshctl", description="Mesh Lifecycle and Topology Control Tool")
    subparsers = parser.add_subparsers(dest="command", required=True)

    # mesh subcommand
    mesh_parser = subparsers.add_parser("mesh")
    mesh_subparsers = mesh_parser.add_subparsers(dest="operation", required=True)

    # mesh create
    c = mesh_subparsers.add_parser("create")
    c.add_argument("-f", required=True, help="YAML file path")
    c.set_defaults(func=cmd_create)

    # mesh list
    l = mesh_subparsers.add_parser("list")
    l.set_defaults(func=cmd_list)

    # mesh describe
    d = mesh_subparsers.add_parser("describe")
    d.add_argument("name", help="Mesh name")
    d.set_defaults(func=cmd_describe)

    # mesh delete
    de = mesh_subparsers.add_parser("delete")
    de.add_argument("name", help="Mesh name")
    de.set_defaults(func=cmd_delete)

    # mesh update
    u = mesh_subparsers.add_parser("update")
    u.add_argument("-f", required=True, help="YAML file path")
    u.set_defaults(func=cmd_update)

    args = parser.parse_args()
    args.func(args)


if __name__ == "__main__":
    main()

